import scala.collection.mutable

def nums(nums: Array[Long]): Long = {
    // 1. Get the set of unique values D_unique from the input array.
    // These are all the possible values that can appear in the array after operations.
    val dUnique = nums.toSet.to[Set[Long]]

    var totalSum: Long = 0

    // 2. For each element n in the original array nums, find the minimum value m_n it can transform into.
    for (n <- nums) {

        // m_n is the smallest d in dUnique such that n is divisible by d.
        val candidates = mutable.HashSet[Long]()

        // Find all divisors of n. O(sqrt(n)).
        var i: Long = 1
        while (i * i <= n) {
            if (n % i == 0) {
                val d1 = i
                val d2 = n / i

                // Check if the divisor d1 is present in the set of unique values.
                if (dUnique.contains(d1)) {
                    candidates.add(d1)
                }
                // Check if the conjugate divisor d2 is present.
                if (dUnique.contains(d2)) {
                    candidates.add(d2)
                }
            }
            i += 1
        }

        // Since n itself is in nums, n is always a candidate divisor of itself, so candidates is non-empty.

        // The minimum value m_n is the smallest element found in the candidates set.
        val m_n = candidates.min

        totalSum += m_n
    }

    totalSum
}
